from __future__ import annotations

import random
from dataclasses import dataclass
from typing import Dict, List

from problemgen.russian.lexicon import NounForms


@dataclass(frozen=True)
class ThemeConfig:
    code: str
    label: str
    location: str
    unit_short: str
    heroes: List[str]
    count_item: NounForms
    choice_a: NounForms
    choice_b: NounForms
    combo_result: NounForms
    route_a: NounForms
    route_b: NounForms
    route_result: NounForms


def _make_theme(
    code: str,
    label: str,
    location: str,
    unit_short: str,
    heroes: List[str],
    count_item: tuple[str, str, str],
    choice_a: tuple[str, str, str],
    choice_b: tuple[str, str, str],
    combo_result: tuple[str, str, str],
    route_a: tuple[str, str, str],
    route_b: tuple[str, str, str],
    route_result: tuple[str, str, str],
) -> ThemeConfig:
    return ThemeConfig(
        code=code,
        label=label,
        location=location,
        unit_short=unit_short,
        heroes=heroes,
        count_item=NounForms(*count_item),
        choice_a=NounForms(*choice_a),
        choice_b=NounForms(*choice_b),
        combo_result=NounForms(*combo_result),
        route_a=NounForms(*route_a),
        route_b=NounForms(*route_b),
        route_result=NounForms(*route_result),
    )


