def get_theme(code: str) -> ThemeConfig:
    if code == "any":
        return THEMES["any"]
    try:
        return THEMES[code]
    except KeyError as error:
        available = ", ".join(sorted(THEMES))
        raise ValueError(f"Неизвестная тема '{code}'. Доступно: {available}") from error


def get_theme_label(code: str) -> str:
    return get_theme(code).label


def sample_theme(code: str, rng: random.Random) -> ThemeConfig:
    if code == "any":
        selectable = [theme for theme in THEMES.values() if theme.code != "any"]
        return rng.choice(selectable)
    return get_theme(code)
